  packs[30].code = `# PowerFactory Python pattern — run inside the supported PF environment
import math
import powerfactory as pf

CONFIG = {
    "study_case": "29_PYTHON_BENCHMARK",
    "scenario": "NORMAL_MAX_EXPORT",
    "variation_stage": "PPM_STAGE_1",
    "study_time": "declared-in-case",
    "method": "AC balanced load flow / ComLdf",
    "command_options": "controlled in Study Case; record project-specific options",
    "model_revision": "TRAINING-R03",
    "script_revision": "W30-EXAMPLE-R02",
    "software_revision": "record installed PowerFactory version/service pack",
    "buses": ["BUS_33_POC", "BUS_11_MAIN", "BUS_11_LOAD"],
}

app = pf.GetApplication()
if app is None:
    raise RuntimeError("PowerFactory application is unavailable")

case = app.GetActiveStudyCase()
if case is None:
    raise RuntimeError("Activate the intended Study Case first")
if case.loc_name != CONFIG["study_case"]:
    raise RuntimeError(f"Wrong Study Case: {case.loc_name!r}")

ldf = app.GetFromStudyCase("ComLdf")
if ldf is None:
    raise RuntimeError("ComLdf is missing from the active Study Case")

rc = ldf.Execute()
if rc != 0:
    raise RuntimeError(f"Load flow failed with return code {rc}")

all_buses = app.GetCalcRelevantObjects("*.ElmTerm") or []
by_name = {bus.loc_name: bus for bus in all_buses}
missing = [name for name in CONFIG["buses"] if name not in by_name]
if missing:
    raise RuntimeError(f"Missing configured terminals: {missing}")
buses = [by_name[name] for name in CONFIG["buses"]]
if len(buses) != 3:
    raise RuntimeError("The benchmark must contain exactly three selected terminals")

rows = []
for bus in buses:
    value = bus.GetAttribute("m:u")
    if value is None or not math.isfinite(float(value)):
        raise RuntimeError(f"Invalid m:u result for {bus.loc_name}: {value!r}")
    rows.append({
        **CONFIG,
        "case": case.loc_name,
        "object": bus.loc_name,
        "quantity": "m:u",
        "unit": "pu",
        "value": float(value),
        "calculation_status": "SUCCESS",
        "limit": None,
        "margin": None,
        "valid": True,
    })
print(rows)`;
  packs[31].code = `// Minimal configuration-driven evaluator (JavaScript illustration)
function evaluate(test, result) {
  const allowedDirection = new Set(["max", "min"]);
  const valid = Boolean(
    allowedDirection.has(test.direction) &&
    test.sourceCurrent && test.inputsComplete && test.modelApproved &&
    Number.isFinite(test.criterion) && Number.isFinite(result.value) &&
    result.calculationSuccess && result.unit === test.unit &&
    test.criterionUnit === test.unit && result.boundary === test.boundary &&
    result.modelRevision === test.modelRevision &&
    result.sourceRevision === test.sourceRevision
  );
  if (!valid) return { status: "INVALID", reason: "Evidence gate failed" };
  const pass = test.direction === "max"
    ? result.value <= test.criterion
    : result.value >= test.criterion;
  return { status: pass ? "PASS" : "FAIL", margin:
    test.direction === "max" ? test.criterion - result.value : result.value - test.criterion };
}

function rollUp(evaluatedRows) {
  if (evaluatedRows.some(r => r.critical && r.status === "FAIL")) return "FAIL";
  if (evaluatedRows.some(r => r.critical && r.status === "INVALID")) return "INVALID";
  if (evaluatedRows.some(r => r.status === "FAIL")) return "FAIL";
  if (evaluatedRows.some(r => r.status === "INVALID")) return "INVALID";
  return evaluatedRows.length && evaluatedRows.every(r => r.status === "PASS") ? "PASS" : "PENDING";
}

// Deliberate QA: run one PASS, one FAIL and one INVALID case, including
// a misspelled direction and a non-finite value. Never coerce missing or failed results to zero.`;

